mapper.select:
SELECT COUNT(*) FROM hm_query.tax_rates_flat

    AND hsn_code = #{hsnCode}
    AND active = #{active}
    AND LOWER(description) LIKE LOWER(CONCAT('%', #{description}, '%'))
    AND (hsn_code LIKE CONCAT('%', #{q}, '%') OR LOWER(description) LIKE LOWER(CONCAT('%', #{q}, '%')))

SELECT id, hsn_code AS "hsnCode", description, gst_rate AS "gstRate",
       cess_rate AS "cessRate", tcs_rate AS "tcsRate",
       effective_from AS "effectiveFrom", effective_to AS "effectiveTo", active
FROM hm_query.tax_rates_flat

    AND hsn_code = #{hsnCode}
    AND active = #{active}
    AND LOWER(description) LIKE LOWER(CONCAT('%', #{description}, '%'))
    AND (hsn_code LIKE CONCAT('%', #{q}, '%') OR LOWER(description) LIKE LOWER(CONCAT('%', #{q}, '%')))

${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.tax_category_mappings_flat

    AND product_category = #{productCategory}
    AND hsn_code = #{hsnCode}
    AND (product_category LIKE CONCAT('%', #{q}, '%') OR description LIKE CONCAT('%', #{q}, '%'))

SELECT id, product_category AS "productCategory", sub_category AS "subCategory",
       hsn_code AS "hsnCode", description
FROM hm_query.tax_category_mappings_flat

    AND product_category = #{productCategory}
    AND hsn_code = #{hsnCode}
    AND (product_category LIKE CONCAT('%', #{q}, '%') OR description LIKE CONCAT('%', #{q}, '%'))

${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.tax_regions_flat

    AND state_code = #{stateCode}
    AND LOWER(state_name) LIKE LOWER(CONCAT('%', #{stateName}, '%'))
    AND union_territory = #{unionTerritory}
    AND (state_name LIKE CONCAT('%', #{q}, '%') OR state_alpha LIKE CONCAT('%', #{q}, '%'))

SELECT id, state_code AS "stateCode", state_name AS "stateName",
       state_alpha AS "stateAlpha", union_territory AS "unionTerritory", active
FROM hm_query.tax_regions_flat

    AND state_code = #{stateCode}
    AND LOWER(state_name) LIKE LOWER(CONCAT('%', #{stateName}, '%'))
    AND union_territory = #{unionTerritory}
    AND (state_name LIKE CONCAT('%', #{q}, '%') OR state_alpha LIKE CONCAT('%', #{q}, '%'))

${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.tax_exemptions_flat

    AND exemption_type = #{exemptionType}
    AND active = #{active}
    AND (exemption_type LIKE CONCAT('%', #{q}, '%') OR description LIKE CONCAT('%', #{q}, '%'))

SELECT id, exemption_type AS "exemptionType", exemption_value AS "value", description,
       full_exemption AS "fullExemption", active
FROM hm_query.tax_exemptions_flat

    AND exemption_type = #{exemptionType}
    AND active = #{active}
    AND (exemption_type LIKE CONCAT('%', #{q}, '%') OR description LIKE CONCAT('%', #{q}, '%'))

${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.order_tax_lines_flat

    AND order_id = #{orderId}
    AND tax_type = #{taxType}
    AND hsn_code = #{hsnCode}

SELECT id, order_id AS "orderId", variant_id AS "variantId", hsn_code AS "hsnCode",
       tax_type AS "taxType", taxable_amount AS "taxableAmount", gst_rate AS "gstRate",
       cgst_amount AS "cgstAmount", sgst_amount AS "sgstAmount", igst_amount AS "igstAmount",
       cess_amount AS "cessAmount", tcs_amount AS "tcsAmount", total_tax AS "totalTax"
FROM hm_query.order_tax_lines_flat

    AND order_id = #{orderId}
    AND tax_type = #{taxType}
    AND hsn_code = #{hsnCode}

${orderby} ${pagination}
